import { useFormik } from "formik";
import LeagueTablePage from "../league-table";

const AdminResult = ()  =>
{
    const submitForm = (values : any) => {
        alert(JSON.stringify(values, null, 2));

    }

    const formik = useFormik({
        initialValues :{
                homeTeam: '', 
                awayTeam: '',
                season: ''},
        onSubmit : values => {
            alert(JSON.stringify(values.homeTeam, null, 2));
        }
    });

    return(

        <>
        <div>hi</div>
        <div>           
            <form onSubmit={formik.handleSubmit} >
                 <input type="text" {...formik.getFieldProps("homeTeam")}/> 
                 <input type="text" {...formik.getFieldProps("awayTeam")}/> 
                 <input type="text" {...formik.getFieldProps("season")}/> 
                 <button type="submit">Go</button>  
            </form>            
        </div>
        </>
    );
}

export default AdminResult;

